/*
 * @method
 * @name aftermath#signTxEd25519
 * @description Helper to sign some transaction bytes and return a generic transaction execution request.
 * @param {object} [tx] transaction bytes and the signing digest for them
 * @returns {object} the input transaction bytes and the signed digest
 */
    pub fn sign_tx_ed25519(&self, mut tx: Value) -> Value {
        if is_greater_than_or_equal(&get_index_of(&self.privateKey, &Value::Str("suiprivkey".to_string())), &Value::Int(0)) {
            panic!("{}", crate::exchange_errors::not_supported(add(&self.id, &Value::Str(" only support hex encoding private key, please transform bech32 encoding private key".to_string()))));
        }
        let mut signingDigest: Value = self.safe_string_k(tx.clone(), "signingDigest", &[]);
        let mut digest: Value = self.base64_to_binary(signingDigest.clone(), &[]);
        let mut privateKey: Value = self.base16_to_binary(self.privateKey.clone(), &[]);
        let mut signature: Value = eddsa(digest.clone(), privateKey.clone(), Value::Str("ed25519".to_string()));
        let mut hexPublicKey: Value = self.safe_string_k(self.options.clone(), "publicKey", &[]);
        if is_equal(&hexPublicKey, &Value::Null) {
            panic!("{}", crate::exchange_errors::arguments_required(add(&self.id, &Value::Str(" requires hex encoding public key in options".to_string()))));
        }
        let mut publicKey: Value = self.base16_to_binary(hexPublicKey.clone(), &[]);
        let mut suiSignature: Value = self.binary_concat(self.base16_to_binary(Value::Str("00".to_string()), &[]), &[self.binary_concat(self.base64_to_binary(signature.clone(), &[]), &[publicKey.clone()])]);
        let mut base64Sig: Value = self.binary_to_base64(suiSignature.clone(), &[]);
        let mut transactionBytes: Value = self.safe_string_k(tx.clone(), "transactionBytes", &[]);
        let mut signatures: Value = Value::List(vec![base64Sig.clone()]);
        return Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("transactionBytes".to_string(), transactionBytes.clone());
        m.insert("signatures".to_string(), signatures.clone());
    m
});

    Value::Null
}

