    pub fn handle_errors(&self, mut httpCode: Value, mut reason: Value, mut url: Value, mut method: Value, mut headers: Value, mut body: Value, mut response: Value, mut requestHeaders: Value, mut requestBody: Value) -> Value {
        if !is_true(&response) {
            return Value::Null;
        }
        //
        // Error with ID: #68498f1e536664f31a7b1aa7
        //
        if is_greater_than_or_equal(&get_index_of(&body, &Value::Str("Error".to_string())), &Value::Int(0)) {
            self.throw_broadly_matched_exception(get_value(&self.exceptions, &Value::Str("broad".to_string())), body.clone(), Value::Str("".to_string()));
            panic!("{}", crate::exchange_errors::exchange_error(body));
        }
        return Value::Null;

    Value::Null
}

